mots = ["ananas", "Banane", "abricot", "cerise", "Avocat"]
compteur = 0

for mot in mots:
    if mot[0].lower() == "a":
        compteur += 1

print(compteur)  # Affiche : 3

nombres = [10, 3, 25, 7, 50, 11, 15]
compteur = 0

for n in nombres:
    if n % 5 == 0:
        compteur += 1

print(compteur)  # Affiche : 4

nombres = [4, 17, 3, 25, 9]
maximum = nombres[0]

for n in nombres:
    if n > maximum:
        maximum = n

print(maximum)  # Affiche : 25

nombres = [2, 3, 6, 8, 7, 9, 10, 12, 13, 15, 17, 24, 13]
impairs = []

for n in nombres:
    if n % 2 != 0:
        impairs.append(n)

print(impairs)  # [3, 7, 9, 13, 15, 17, 13]
